export type MusicItem = {
  name: string
  src: string
}

export type ConfettiShape = 'star' | 'colored-paper'

export type ConfettiConfig = {
  shape?: ConfettiShape
  shapes?: string | string[]
  secondary?: boolean
}

/** 自定义主题属性，消费方通过 & 组合到 DefaultTheme.Config */
export interface FxThemeCustomConfig {
  musicBall?: {
    enable?: boolean
    visible?: boolean
    autoplay?: boolean
    loop?: boolean
    src?: string
    list?: MusicItem[]
  }
  confetti?: boolean | ConfettiConfig
  /** 自动提取 hero 图片颜色作为背景光晕和代码块光束颜色，默认 false */
  heroImageColor?: boolean
  /** 启用平滑滚动，右侧大纲导航点击时平滑滚动到对应位置，默认 false */
  smoothScroll?: boolean
  /** 代码块折叠，默认 true 启用。可配置折叠行数阈值 */
  codeBlockFold?: boolean | {
    /** 超过多少行折叠，默认 10 */
    lines?: number
  }
}

// fxConfig 不引用 vitepress 内部类型，避免跨模块类型冲突
// 运行时实际值包含完整配置（在 .vitepress/config/index.ts 源码中维护）
declare const fxConfig: {
  markdown?: { lineNumbers?: boolean }
  transformPageData?: (pageData: any) => any
  vite?: { ssr?: { noExternal?: string[] } }
}
export default fxConfig
